    BitSet32() : bits(0) {}
    void set(int i) { bits |= (uint32_t)(1u << i); }
    void clear(int i) { bits &= ~(uint32_t)(1u << i); }
    bool get(int i) const { return (bits >> i) & 1u; }
    int count() const {
        int c = 0;
        uint32_t b = bits;
        while (b) { c += (int)(b & 1u); b >>= 1; }
        return c;
    }
};

